var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"오늘의 마지막 품목은 북유럽 유류품 보관소에서 회수된 크리스털 샹들리에입니다.","JPN":"今日の最後の品は、北ヨーロッパの遺留品保管所から回収された、クリスタルのシャンデリアです。","ENG":"The last item of the day is an antique crystal chandelier from northern Europe.","TWN":"今天最後一個商品是北歐遺物保管所回收的水晶吊燈。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"1896년 추락 사건을 일으켰고, 오페라를 통해 널리 알려진 아티팩트죠.","JPN":"1896年に墜落事件を起こし、オペラを通じて広く知れ渡ったアーティファクトです。","ENG":"It's an Artifact whose crash in 1896 has been widely retold through an opera.","TWN":"1896年引發了墜機事件，透過歌劇而廣為人知的人造神器。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"경매가는 100만 크레딧부터 시작하죠. 100만 크레딧 있으십니까?","JPN":"では、100万クレジットから始めます。100万クレジット、どなたかいらっしゃいますか？","ENG":"We'll begin the auction at 1 million Credits. Do I hear 1 million Credits?","TWN":"拍賣底價是100萬金幣，有出100萬金幣的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"249번, 270만 크레딧으로 입찰하셨습니다. 감사합니다.","JPN":"249番、270万クレジットで入札されました。ありがとうございます。","ENG":"We've got 2.7 million from 249. Thank you.","TWN":"249號顧客，出價270萬金幣。謝謝。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L8_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"249번께서 270만 크레딧으로 입찰하셨습니다. 더 안 계십니까?","JPN":"249番、270万クレジットで入札されました。他の方、いらっしゃいませんか？","ENG":"Number 249 has bid for 2.7 million. Anyone else?","TWN":"249號顧客出價270萬金幣，還有要出價的客人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BODYGUARD_NPC_NULL_NULL","text":{"KOREA":"말씀하셨던 것보다 낮은 가격이군요.","JPN":"仰った値段より低いですね。","ENG":"It's going for a lot less than you suggested.","TWN":"這個價格比您說的要低啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"저들이 보기엔 이 가격도 터무니없이 높아 보이겠지. 무지한 자들에겐 부피만 큰 골동품일 뿐이니까.","JPN":"あいつらには、これでも高すぎるだろう。無知な者には、体積だけ大きい骨董品だからな。","ENG":"It probably seems outrageously overpriced in their eyes. To the ignorant, it's nothing but a clunky antique.","TWN":"想必在那些人眼裡，這個價格已經高得離譜了。因為對無知的人來說，這就只是個較大的古董而已。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"아, 337번 입찰하셨습니다. 280만 크레딧 나왔습니다.","JPN":"あ、337番の方が入札されました。280万クレジットです。","ENG":"Oh, we've got a bid from 337. 2.8 million Credits.","TWN":"啊，337號顧客出價了，280萬金幣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"입찰했다고?","JPN":"入札しただと？","ENG":"Someone made a bid?","TWN":"出價了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"337번이라면......","JPN":"337番なら……","ENG":"337? Let's see...","TWN":"337號的話……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"설마...... 저 새파랗게 어린 아가씨가?","JPN":"まさか……あの若い小娘が？","ENG":"No... That little girl?","TWN":"該不會……是那個年紀輕輕的小姑娘？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BODYGUARD_NPC_NULL_NULL","text":{"KOREA":"어떻게 하시겠습니까. 준비해 온 자금이 아직 남아 있긴 합니다만......","JPN":"いかがなさいますか？　資金はまだ残っていますが……","ENG":"What's it going to be? We still have some funds left...","TWN":"怎麼辦？準備的資金雖然還有剩，可是……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"무리를 해서라도 낙찰 받아야지. 빈손으로 돌아가면 학회장님께 연락드릴 면목이 없어.","JPN":"無理をしてでも落札しよう。手ぶらで帰ると学会長に合わせる顔がないからな。","ENG":"We'll have to win it even if we have to go a little over budget. I won't let the President down by going back empty-handed.","TWN":"不管怎樣一定要拍下來。空手而歸的話，就沒臉去見學會會長了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"249번, 300만 크레딧으로 입찰하셨습니다.","JPN":"249番、300万クレジットで入札されました。","ENG":"We've got 3 million from 249.","TWN":"249號顧客，出價300萬金幣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"사, 337번. 400만 크레딧을 호가하셨습니다.","JPN":"さ、337番、400万クレジットです。","ENG":"Oh, 337... has bid for 4 million.","TWN":"喔，337號顧客，叫價400萬金幣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L33_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"실례지만 337번 참석자님, 주최 측 일각에선 귀하께 지불 능력이 있는지 의문을 품고 있습니다만......","JPN":"失礼ですが、337番様。主催側の一部で、支払能力が疑われているようですが……","ENG":"Excuse me, young madam at 337, but this auction house is curious whether you'd be able to issue the payment for your bid...","TWN":"很抱歉，337號顧客，主辦單位的一些人懷疑您是否具備支付能力……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"경매장의 급을 떨어뜨릴 만큼 무례한 발언이군요.","JPN":"オークションの品格を落とす、無礼な発言ですね。","ENG":"Well, what a terribly rude thing to ask. I thought this auction house would never be so rudimentary.","TWN":"你真是無禮，這個拍賣場就是這麼對待客人的嗎。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 정도 금액으로 아쉬운 소리나 할 만큼 궁핍한 형편은 아니랍니다. 염려 마시길.","JPN":"その程度の金額は、私のお小遣いに過ぎませんわ。ご心配なく。","ENG":"I can afford to set aside such a paltry sum for a trinket or two. You need not worry.","TWN":"這點錢我還是拿得出來的，不用擔心。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BODYGUARD_NPC_NULL_NULL","text":{"KOREA":"400만 크레딧이면...... 이번에 준비한 자금으로는 어려운 액수입니다.","JPN":"400万クレジットは……現在用意されている資金では厳しいと思われます。","ENG":"4 million Credits... We haven't prepared enough money to outbid that.","TWN":"400萬金幣的話……這次準備的資金是不夠了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"일이 복잡하게 됐군. 이번에 고용했던 녀석들을 준비시키게.","JPN":"困ったな。雇っておいたやつらに任せよう。","ENG":"That complicates things. Fine. Have the men we hired get ready.","TWN":"事情難辦了。叫這次雇的那些人準備好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BODYGUARD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"337번, 400만 크레딧으로 입찰하셨습니다. 호가가 없으므로 낙찰을 선언합니다.","JPN":"337番、400万クレジットで入札されました。他の方がいらっしゃらないようなので、落札を宣言します。","ENG":"We've got 4 million from 337. Going once, going twice... Sold.","TWN":"337號顧客，出價400萬金幣。沒人叫價的話我就宣佈成交了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 400만 크레딧이라니 샹들리에 하나에 거금을 들이셨군요.","JPN":"はは、400万クレジットとは。高いシャンデリアですね。","ENG":"Hah hah, 4 million Credits? That's quite a fortune to spend on a chandelier.","TWN":"哈哈，400萬金幣，一個吊燈居然花這麼大的錢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"내버려 두면 사고나 치고 다닐 흉물이에요. 적어도 사람 손이 닿지 않는 곳에 보관해야죠.","JPN":"放っておけば事件を起こす、厄介な品です。少なくとも、人目につかない所に保管するべきですわ。","ENG":"It's only going to hurt more people if we let it stay out there. The least we can do is keep it out of reach.","TWN":"那可是兇器，怎麼能讓別人拿去。至少要放在人們接觸不到的地方保管才行。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"동감입니다. 가까운 시설에 자리를 만들어 두라고 전해 두죠.","JPN":"同感です。近くの施設に伝えておきます。","ENG":"I couldn't agree more. I'll have them make room in a nearby facility.","TWN":"不錯，我會在附近的設施中安排個地方。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"はあ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨? 무슨 일 있으십니까?","JPN":"お嬢様？　どうなさいましたか？","ENG":"My lady? Is there a problem?","TWN":"小姐？有什麼事嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"불청객이 나타났어요. 잠시 후 다시 연락하죠.","JPN":"招かれざる客です。後ほど、また連絡します。","ENG":"Looks like we've got ourselves some unwelcome guests. I'll call you again in a few minutes.","TWN":"有個不速之客來了，我待會再聯絡你。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"눈치는 있나 보군. 애먼 사람 엮이게 만들어서 좋을 것 없지.","JPN":"機転が利くな。関係ないやつを巻き込んでいいことはないからな。","ENG":"So you're not completely clueless, eh. I suppose there's no harm in avoiding collateral damage.","TWN":"很敏銳嘛。畢竟讓無辜的人捲進來可沒什麼好處。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제 앞에서 신분을 밝히지 않는 무례 정도는 눈감아 드리죠.","JPN":"私の前で身分を明かさないとは。非常に無礼ですが、許してあげましょう。","ENG":"I'll overlook the rudeness of not identifying yourself.","TWN":"我就不計較你們不自報姓名的無禮之舉了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"용건이 있다면 말씀해 보세요. 허락하겠습니다.","JPN":"それで、ご用件は？","ENG":"You may state the purpose of your accostment, then. I'll allow it.","TWN":"有事就說吧。我允許你們發言。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"경매장에서 낙찰 받은 물건을 넘겨. 험한 꼴 보기는 싫겠지.","JPN":"オークションで落札した品を渡せ。ひどい目に遭いたくないだろ？","ENG":"Hand over the item you won from the auction. Trust me, you won't like it when I rough you up.","TWN":"把妳在拍賣場拍下的東西交出來，否則就有妳好看的了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"정장도 안 입고 말을 걸 때부터 짐작했지만, 하나부터 열까지 야만스럽군요.","JPN":"スーツも着ないで、レディに話しかけた時から予想はしてましたが。実に野蛮ですわ。","ENG":"I had a feeling you may be quite the philistine based on your totally inappropriate habiliments.","TWN":"連個西裝也沒穿，我從你對我搭話時就在想是不是這樣了，但你還真是徹頭徹尾地粗鄙呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"비키세요. 당신들 상대로 시간을 허비하기 아깝습니다.","JPN":"おどきなさい。あなた方の相手をする時間がもったいないわ。","ENG":"Step aside. I don't have the time to waste on the likes of you.","TWN":"讓開，我可不想在你們身上浪費時間。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"오, 세상 물정을 모르나 본데 요새는 정장보다 이게 잘 먹히거든.","JPN":"はあ、世間知らずだな。最近はこっちの方がイケてるんだよ。","ENG":"You'd be surprised how far this outfit can take you these days, princess.","TWN":"噢，妳好像沒怎麼見過世面啊。比起西裝，最近這個更吃香呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_SHOTGUN_RELOAD_SMALL"},{"id":"L18_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"숨만 붙여 둬! 물건은 접수해야 한다!","JPN":"殺さなければ何をしても構わん！　例の品を奪え！","ENG":"You can go all out lads, as long as she's still breathing after this! But make sure you secure the package!","TWN":"留她一口氣！東西一定要搶到手！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"이, 이런 젠장...... 카운터까지 있었는데 어떻게......","JPN":"ち、ちくしょう……カウンターもいたのに、どうして……","ENG":"D-darn it... We even brought a Counter along... How come...","TWN":"這，該死……明明都有制裁者了，怎麼會……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신들과 저는 겨우살이와 카두풀 꽃만큼 격이 다르답니다. 당연한 결과죠.","JPN":"あなた方と私は、宿り木と花ほどの差があるんです。なので、これは当然の結果ですわ。","ENG":"We're about as different as rhinestones and diamonds, I'm afraid. This was only to be expected.","TWN":"你們跟我就好比槲寄生與卡杜草花，格調就是不一樣，這是理所當然的結果。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L27_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"큭......! 운 좋게 얻은 시계 가지고 잘난 척 하기는......!","JPN":"くっ……！　ただ運が良かっただけだろ？　偉そうにしてるんじゃねえ……！","ENG":"Ugh! You'd be nothing without that Watch!","TWN":"咳……！不過是運氣好得到了手錶而已，還一副好了不起的樣子……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘난 척이 아니라 잘났답니다.","JPN":"偉そうなのではなく、偉いんです。","ENG":"Oh, I hardly doubt it. I'm far superior to the likes of you.","TWN":"你說得不錯，我是真的了不起。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"자, 잘났다고?","JPN":"え、偉い？","ENG":"S-superior?","TWN":"了、了不起？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 전 객관적이고 명백하게 잘났어요.","JPN":"ええ。私は客観的に見ても偉いと言えますわ。","ENG":"That's right. I'm superior to you in every objective, measurable way.","TWN":"對，客觀準確地說，我的確很了不起。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"가끔은...... 이렇게 잘나도 괜찮을까 싶을 정도죠.","JPN":"時々……こんなに偉くていいのかしら、と思ってしまうほどです。","ENG":"Sometimes... it almost seems criminal how superior I am.","TWN":"甚至……偶爾我會因自己太了不起了，而感到不安呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"그, 그래......?","JPN":"そ、そうなのか……？","ENG":"O-oh yeah?","TWN":"是、是嗎……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 앞으로 체통을 지키고 싶으시다면 사람 보는 안목부터 키우도록 하세요.","JPN":"ですから、これからは人を見る目を養った方がいいでしょうね。そうすれば、恥をかかずに済みますから。","ENG":"I suggest you develop a better judge of character if you'd like to preserve your dignity from now on.","TWN":"所以，以後要想保持體面的話，還是先培養看人的眼光吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"체통을 지켜야 하는 건 아가씨입니다.","JPN":"お嬢様、また勝手にお出かけになったのですね。","ENG":"If I may, I fear you're the one who should be more mindful of your dignity, my lady.","TWN":"該保持體面的人是小姐您呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L37_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"모건에게 들었습니다. 또 보좌관도 대동하지 않고 외출하셨더군요.","JPN":"タデウスから聞きました。補佐官も連れずに一人で外出されるとは。","ENG":"Morgan has informed me. You've set out without an aide again.","TWN":"我聽摩根說了，您又不帶輔助人員就出去了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"게다가 상의 없이 공금을 쓰시다니, 윗사람이라면 자고로 실무자들의 고충을......","JPN":"その上何の相談もなく、公金までお使いになりましたね？　上に立つ者は、実務者の苦労を……","ENG":"Worse yet, you've appropriated the Institution funds without due consultation. As a leader, you really ought to be more mindful of how your staff tirelessly—","TWN":"甚至未經商議就動用公款，自古以來，上級就應該體恤實務人員的辛苦……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실례. 잠시 통신기에 혼선이 일어난 모양이네요.","JPN":"失礼。通信機が混線したようですわ。","ENG":"Pardon me. I believe there's been a glitch in the communication system.","TWN":"抱歉，通信器好像暫時出現雜音。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":"누군지 몰라도 구구절절 옳은 소리만 하던 것 같던데......","JPN":"何者だか知らないが、言ってることは正しい……","ENG":"Whoever that was sounds like a wise fella...","TWN":"雖然不知道對方是誰，但他說的話好像都很有道理……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERCENARY2_NPC_NULL_NULL","text":{"KOREA":" 크억!","JPN":"ガハッ！","ENG":" Ack!","TWN":"唔啊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY2_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG_02"},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잔소리꾼에게 찬동할 거면 그냥 조용히 기절해 계세요. 배후는 나중에 물을 테니까요.","JPN":"あの小言に賛同するなら、黙ってもらいます。依頼者は後ほど伺いますので。","ENG":"You might as well as stay unconscious if you're going to sympathize with a carper. I'll interrogate you about your employer later.","TWN":"要是你贊同那個嘮叨傢伙的話，就請你閉嘴昏過去吧。你的幕後主使是誰，我之後會再問你。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"페리어도 하여간...... 아직도 어린애 취급이라니.","JPN":"まったく、フェリエーったら……まだ子供扱いするのね。","ENG":"Ferrier, that old fool... He's still treating me like a child.","TWN":"瑞里也真是的……還把我當小孩子看。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};